 1	import React, { FC, ReactNode, useState } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import {
 5	  Card,
 6	  CardBody,
 7	  CardHeader,
 8	  ExpandableSection,
 9	  Title,
10	  TitleSizes,
11	  Tooltip,
12	} from '@patternfly/react-core';
13	import { OutlinedQuestionCircleIcon } from '@patternfly/react-icons';
14	
15	import './GettingStartedGrid.scss';
16	
17	type GettingStartedGridProps = {
18	  children?: ReactNode[];
19	};
20	
21	export const GettingStartedGrid: FC<GettingStartedGridProps> = ({ children }) => {
22	  const { t } = useKubevirtTranslation();
23	  const [isExpanded, setIsExpanded] = useState(true);
24	
25	  const title = t('Getting started resources');
26	  const titleTooltip = t(
27	    'Use our collection of resources to help you get started with virtualization.',
28	  );
29	
30	  return (
31	    <Card className="kv-getting-started-grid" data-test="getting-started">
32	      <ExpandableSection
33	        toggleContent={
34	          <Title data-test="title" headingLevel="h2" id="tour-step-resources" size={TitleSizes.lg}>
35	            {title}{' '}
36	            <Tooltip className="kv-getting-started-grid__tooltip" content={titleTooltip}>
37	              <span
38	                aria-label={t('More info')}
39	                className="kv-getting-started-grid__tooltip-icon"
40	                role="button"
41	              >
42	                <OutlinedQuestionCircleIcon />
43	              </span>
44	            </Tooltip>
45	          </Title>
46	        }
47	        className="kv-getting-started-grid__expandable pf-m-display-lg"
48	        isExpanded={isExpanded}
49	        onToggle={(_, expand) => setIsExpanded(expand)}
50	      >
51	        <CardHeader className="kv-getting-started-grid__header" />
52	        <CardBody className="kv-getting-started-grid__content">{children}</CardBody>
53	      </ExpandableSection>
54	    </Card>
55	  );
56	};

